SELECT COUNT(1)
  FROM TRAVEL_PLAN
 WHERE HOST_MEMBER_NO = #{memberNo}

SELECT COUNT(1)
  FROM TRAVEL_INVITATION
 WHERE TRAVEL_PLAN_NO    = #{planNo}
   AND INVITEE_MEMBER_NO = #{inviteeMemberNo}
   AND INVITE_STATUS     = 'PENDING'

mapper.update:
UPDATE TRAVEL_INVITATION
   SET INVITE_STATUS = #{status}
 WHERE TRAVEL_INVITATION_NO = #{invitationNo}
   AND INVITEE_MEMBER_NO    = #{memberNo}
   AND INVITE_STATUS        = 'PENDING'

mapper.select:
SELECT TRAVEL_PLAN_NO
  FROM TRAVEL_PLAN
 WHERE HOST_MEMBER_NO = #{memberNo}

mapper.delete:
DELETE FROM TRAVEL_PLAN
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND HOST_MEMBER_NO = #{hostMemberNo}

mapper.update:
UPDATE PLAN_GUEST
   SET CAN_EDIT = #{canEdit}
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND MEMBER_NO      = #{memberNo}

mapper.select:
SELECT COUNT(*)
  FROM PLAN_GUEST
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND MEMBER_NO      = #{memberNo}

SELECT PLAN_GUEST_NO
  FROM PLAN_GUEST
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND MEMBER_NO      = #{memberNo}

mapper.delete:
DELETE FROM PLAN_GUEST
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND MEMBER_NO      = #{memberNo}

mapper.update:
UPDATE TRAVEL_PLAN
   SET HOST_MEMBER_NO = #{newHostMemberNo}
 WHERE TRAVEL_PLAN_NO  = #{planNo}
   AND HOST_MEMBER_NO  = #{currentHostMemberNo}

UPDATE TRAVEL_PLAN
   SET IS_PUBLIC     = #{isPublic}
 WHERE TRAVEL_PLAN_NO = #{planNo}
   AND HOST_MEMBER_NO = #{hostMemberNo}

UPDATE TRAVEL_PLAN
   SET TRAVEL_NAME      = #{title}
     , TRAVEL_THEME_CD  = (SELECT TRAVEL_THEME_CD FROM TRAVEL_THEME WHERE TRAVEL_THEME_NM = #{theme})
     , TRAVEL_START_DT  = TO_DATE(#{startDate}, 'YYYY-MM-DD')
     , TRAVEL_END_DT    = TO_DATE(#{endDate},   'YYYY-MM-DD')
     , OUTLINE          = #{overview}
     , REVISION_DT      = SYSDATE
 WHERE TRAVEL_PLAN_NO   = #{id}
   AND HOST_MEMBER_NO   = #{hostMemberNo}
